// ── Build Weekly Digest HTML ──

const stats = $input.all()[0].json;

const weekStart = stats.week_start || new Date(Date.now() - 7 * 86400000).toISOString().slice(0, 10);
const weekEnd = new Date(new Date(weekStart).getTime() + 6 * 86400000).toISOString().slice(0, 10);

const intercepted   = stats.accounts_intercepted   || 0;
const conversations = stats.conversations_started   || 0;
const prevented     = stats.churn_prevented          || 0;
const escalations   = stats.csm_escalations          || 0;
const sent          = stats.messages_sent             || 0;
const replied       = stats.messages_replied           || 0;
const replyRate     = sent > 0 ? ((replied / sent) * 100).toFixed(1) : '0.0';

const critical = stats.critical_count || 0;
const high     = stats.high_count     || 0;
const medium   = stats.medium_count   || 0;
const low      = stats.low_count      || 0;
const total    = stats.total_accounts || 0;
const avgProb  = stats.avg_churn_prob || 0;

const kpiRow = (label, value, color) =>
  `<td style="text-align:center;padding:16px;">`
  + `<div style="font-size:32px;font-weight:bold;color:${color};">${value}</div>`
  + `<div style="font-size:13px;color:#6b7280;margin-top:4px;">${label}</div>`
  + `</td>`;

const riskBar = (label, count, color) => {
  const pct = total > 0 ? ((count / total) * 100).toFixed(1) : 0;
  return `<tr>`
    + `<td style="padding:6px 12px;font-weight:600;color:${color};">${label}</td>`
    + `<td style="padding:6px 12px;text-align:right;">${count}</td>`
    + `<td style="padding:6px 12px;text-align:right;color:#6b7280;">${pct}%</td>`
    + `</tr>`;
};

const html = `
<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;padding:24px;background:#ffffff;">
  <div style="text-align:center;margin-bottom:32px;">
    <h1 style="color:#1a1a2e;margin:0;">NovaSeat — Weekly Churn Report</h1>
    <p style="color:#6b7280;margin:8px 0 0;">${weekStart} to ${weekEnd}</p>
  </div>

  <table style="width:100%;border-collapse:collapse;margin-bottom:32px;">
    <tr style="background:#f8f7ff;border-radius:8px;">
      ${kpiRow('Accounts Intercepted', intercepted, '#4f46e5')}
      ${kpiRow('Conversations Started', conversations, '#0891b2')}
      ${kpiRow('Churn Prevented', prevented, '#16a34a')}
      ${kpiRow('CSM Escalations', escalations, '#dc2626')}
    </tr>
  </table>

  <table style="width:100%;border-collapse:collapse;margin-bottom:32px;">
    <tr style="background:#f8f7ff;">
      ${kpiRow('Messages Sent', sent, '#4f46e5')}
      ${kpiRow('Replies Received', replied, '#0891b2')}
      ${kpiRow('Reply Rate', replyRate + '%', '#16a34a')}
    </tr>
  </table>

  <h2 style="color:#1a1a2e;font-size:18px;margin-bottom:12px;">Current Risk Distribution</h2>
  <table style="width:100%;border-collapse:collapse;margin-bottom:32px;">
    <thead><tr style="border-bottom:2px solid #e5e7eb;">
      <th style="text-align:left;padding:8px 12px;">Tier</th>
      <th style="text-align:right;padding:8px 12px;">Accounts</th>
      <th style="text-align:right;padding:8px 12px;">%</th>
    </tr></thead>
    <tbody>
      ${riskBar('Critical', critical, '#dc2626')}
      ${riskBar('High', high, '#f59e0b')}
      ${riskBar('Medium', medium, '#3b82f6')}
      ${riskBar('Low', low, '#16a34a')}
    </tbody>
    <tfoot><tr style="border-top:2px solid #e5e7eb;font-weight:bold;">
      <td style="padding:8px 12px;">Total</td>
      <td style="padding:8px 12px;text-align:right;">${total}</td>
      <td style="padding:8px 12px;text-align:right;">Avg prob: ${(avgProb * 100).toFixed(1)}%</td>
    </tr></tfoot>
  </table>

  <p style="color:#9ca3af;font-size:12px;text-align:center;">Generated automatically by NovaSeat Churn Prevention Platform</p>
</div>
`;

return [{
  json: {
    weekStart,
    weekEnd,
    intercepted,
    conversations,
    prevented,
    escalations,
    sent,
    replied,
    replyRate: parseFloat(replyRate),
    reportHtml: html,
    reportData: {
      risk_distribution: { critical, high, medium, low, total },
      avg_churn_probability: avgProb,
      kpis: { intercepted, conversations, prevented, escalations, sent, replied }
    }
  }
}];
